using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;
using System.IO;

namespace FileServer.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly string _uploadsFolder;

        public FilesController(IWebHostEnvironment env)
        {
            _uploadsFolder = Path.GetFullPath(Path.Combine(env.ContentRootPath, "uploads"));
        }

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            // Step 1: Reject filenames that are null/empty or contain obvious traversal characters
            if (string.IsNullOrWhiteSpace(filename))
            {
                return BadRequest("Filename is required.");
            }

            // Step 2: Extract just the filename component, stripping any directory separators
            // This defends against inputs like "../../etc/passwd" or "subdir/../../secret"
            string sanitizedFilename = Path.GetFileName(filename);

            if (string.IsNullOrWhiteSpace(sanitizedFilename))
            {
                return BadRequest("Invalid filename.");
            }

            // Step 3: Combine with the uploads base directory and resolve to a full canonical path
            string requestedPath = Path.GetFullPath(Path.Combine(_uploadsFolder, sanitizedFilename));

            // Step 4: Verify the resolved path is strictly within the uploads directory
            // Use OrdinalIgnoreCase for Windows compatibility; on Linux you may use Ordinal
            if (!requestedPath.StartsWith(_uploadsFolder + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase)
                && !requestedPath.Equals(_uploadsFolder, StringComparison.OrdinalIgnoreCase))
            {
                return BadRequest("Invalid file path.");
            }

            // Step 5: Check that the file actually exists
            if (!System.IO.File.Exists(requestedPath))
            {
                return NotFound("File not found.");
            }

            // Step 6: Determine the content type based on the file extension
            string contentType = GetContentType(sanitizedFilename);

            // Step 7: Return the file with the appropriate content type
            var fileStream = new FileStream(requestedPath, FileMode.Open, FileAccess.Read, FileShare.Read);
            return File(fileStream, contentType, sanitizedFilename);
        }

        [HttpGet("info/{filename}")]
        public IActionResult GetFileInfo(string filename)
        {
            if (string.IsNullOrWhiteSpace(filename))
            {
                return BadRequest("Filename is required.");
            }

            string sanitizedFilename = Path.GetFileName(filename);

            if (string.IsNullOrWhiteSpace(sanitizedFilename))
            {
                return BadRequest("Invalid filename.");
            }

            string requestedPath = Path.GetFullPath(Path.Combine(_uploadsFolder, sanitizedFilename));

            if (!requestedPath.StartsWith(_uploadsFolder + Path.DirectorySeparatorChar, StringComparison.OrdinalIgnoreCase)
                && !requestedPath.Equals(_uploadsFolder, StringComparison.OrdinalIgnoreCase))
            {
                return BadRequest("Invalid file path.");
            }

            if (!System.IO.File.Exists(requestedPath))
            {
                return NotFound("File not found.");
            }

            var fileInfo = new FileInfo(requestedPath);

            return Ok(new
            {
                Name = fileInfo.Name,
                Size = fileInfo.Length,
                ContentType = GetContentType(sanitizedFilename),
                LastModified = fileInfo.LastWriteTimeUtc
            });
        }

        private static string GetContentType(string filename)
        {
            var provider = new FileExtensionContentTypeProvider();

            // Add any custom mappings not included by default
            provider.Mappings[".md"] = "text/markdown";
            provider.Mappings[".csv"] = "text/csv";
            provider.Mappings[".dwg"] = "application/acad";
            provider.Mappings[".webp"] = "image/webp";
            provider.Mappings[".avif"] = "image/avif";

            if (!provider.TryGetContentType(filename, out string? contentType))
            {
                // Default to octet-stream for unknown file types
                contentType = "application/octet-stream";
            }

            return contentType;
        }
    }
